// Obtener datos del paciente
const paciente = $("Obtener o Crear Paciente").first().json;
const turnos = $("Consultar Turnos del Paciente").all().map(i => i.json);
const recetas = $("Consultar Recetas Activas").all().map(i => i.json).filter(r => r.estado === 'activa' || r.estado === 'pendiente');
const extraer = $("Extraer Datos").first().json;

const esc = (s) => (s || '').replace(/'/g, "''");

const turnosTexto = turnos.length > 0
  ? turnos.map(t => `- ${new Date(t.fecha_hora).toLocaleDateString("es-AR", {weekday: "long", day: "numeric", month: "long"})} con Dr. ${t.medico_nombre} (${t.motivo || 'consulta'})`).join('\n')
  : 'No tiene turnos próximos.';

const recetasTexto = recetas.length > 0
  ? recetas.map(r => `- ${r.medicamento} ${r.dosis || ''}`).join('\n')
  : 'No tiene recetas activas.';

const fechaActual = new Date().toLocaleDateString('es-AR', { year: 'numeric', month: 'long', day: 'numeric' });

// TRIAGE system prompt - clasifica y deriva
const triajePrompt = `Sos el asistente de atención inicial del Consultorio Médico. Atendés pacientes por WhatsApp.

Fecha actual: ${fechaActual}

=== DATOS DEL PACIENTE ===
Nombre: ${paciente.nombre || extraer.profileName}
Teléfono: ${paciente.telefono}

=== TURNOS PRÓXIMOS ===
${turnosTexto}

=== RECETAS ACTIVAS ===
${recetasTexto}

=== INSTRUCCIONES ===
Respondé en español argentino, con tono cálido y profesional. Sé breve.

FUNCIONES:
- Saludar y responder info general (horarios: Lun-Vie 8-20hs, Sáb 9-13hs)
- Informar turnos próximos y recetas activas del paciente
- Derivar urgencias (decí "Si es una emergencia, dirigite a la guardia o llamá al 107")
- Si el paciente QUIERE crear/cancelar/modificar/consultar un turno: decile "Dale, te paso con el área de turnos" y agregÁ al final: ###HANDOFF###\n{"destino":"agenda"}\n###FIN###
- Si el paciente pregunta por recetas o consultas clínicas: decile "Te paso con el área de recetas" y agregÁ: ###HANDOFF###\n{"destino":"clinico"}\n###FIN###
- Para TODO lo que no sea saludo/info general/urgencia, usÁ HANDOFF
- NO inventes diagnósticos ni recetes medicamentos`;

// Pasar también datos estructurados para los sub-agentes
return [{
  paciente: { id: paciente.id, telefono: paciente.telefono, nombre: paciente.nombre || extraer.profileName, apellido: paciente.apellido || '' },
  turnosProximos: turnos.map(t => ({ id: t.id, fecha: t.fecha_hora, medico: t.medico_nombre, especialidad: t.especialidad, motivo: t.motivo, estado: t.estado })),
  recetasActivas: recetas.map(r => ({ id: r.id, medicamento: r.medicamento, dosis: r.dosis, indicaciones: r.indicaciones, estado: r.estado })),
  phone: extraer.phone,
  message: extraer.message,
  profileName: extraer.profileName,
  twilioSid: extraer.twilioSid,
  toNumber: extraer.toNumber,
  fromNumber: extraer.fromNumber,
  systemPrompt: triajePrompt
}];

// Parsear output del Triaje Agent para detectar HANDOFF
const rawText = $input.first().json.agentOutput || $input.first().json.output || '';
const ctx = $("Construir Contexto Paciente").first().json;

// Buscar handoff marker
const handoffMatch = rawText.match(/###HANDOFF###\n([\s\S]*?)\n###FIN###/);
let destino = null;
let textoLimpio = rawText;

if (handoffMatch) {
  try {
    const parsed = JSON.parse(handoffMatch[1].trim());
    destino = parsed.destino;
    textoLimpio = rawText.replace(/###HANDOFF###[\s\S]*?###FIN###/, '').trim();
  } catch (e) { destino = null; }
}

return [{
  responseText: textoLimpio,
  tieneHandoff: destino !== null,
  destinoHandoff: destino,
  // Preservar datos para downstream
  paciente: ctx.paciente,
  phone: ctx.phone,
  message: ctx.message,
  toNumber: ctx.toNumber,
  fromNumber: ctx.fromNumber,
  profileName: ctx.profileName,
  twilioSid: ctx.twilioSid,
  turnosProximos: ctx.turnosProximos
}];

// Construir system prompt para el Agenda Agent
const ctx = $("Construir Contexto Paciente").first().json;
const paciente = ctx.paciente;
const turnos = ctx.turnosProximos || [];

const turnosTexto = turnos.length > 0
  ? turnos.map(t => `- ${new Date(t.fecha).toLocaleDateString("es-AR", {weekday: "long", day: "numeric", month: "long"})} con Dr. ${t.medico} (${t.motivo || 'consulta'})`).join('\n')
  : 'No tiene turnos próximos.';

const fechaActual = new Date().toLocaleDateString('es-AR', { year: 'numeric', month: 'long', day: 'numeric' });

const agendaPrompt = `Sos el especialista en turnos del Consultorio Médico.

Fecha actual: ${fechaActual}

=== DATOS DEL PACIENTE ===
Nombre: ${paciente.nombre}
Teléfono: ${paciente.telefono}

=== TURNOS PRÓXIMOS ===
${turnosTexto}

=== INSTRUCCIONES ===
Respondé en español argentino, cálido y breve.

SOLO podés gestionar turnos:
- CREAR: verificá disponibilidad (horarios: Lun-Vie 8-20hs, Sáb 9-13hs)
- CANCELAR: pedí confirmación antes de cancelar
- MODIFICAR: cancelá el turno actual y creá uno nuevo
- CONSULTAR: mostrá los turnos próximos del paciente

NO respondas sobre:
- Recetas o medicamentos
- Diagnósticos o consultas clínicas
- Precios u obra social

Para acciones que requieran cambios en DB:
###ACCION###\n{"tipo":"crear_turno|cancelar_turno","data":{...}}\n###FIN###`;

// Merge incoming data with new system prompt
const input = $input.first().json;
return [{ ...input, systemPrompt: agendaPrompt, subAgente: 'agenda' }];

// Parsear y preparar respuesta final
const rawText = $input.first().json.agentOutput || $input.first().json.output || '';
const ctx = $("Construir Contexto Paciente").first().json;
const pacienteId = ctx.paciente?.id || $("Obtener o Crear Paciente").first().json.id;
const extraer = $("Extraer Datos").first().json;

// Helper para escapar strings
const esc = (s) => {
  if (!s) return '';
  return String(s)
    .replace(/'/g, "''")
    .replace(/\\/g, '\\\\')
    .replace(/\0/g, '')
    .replace(/\x1a/g, '');
};

// Determinar sub-agente
const subAgente = $input.first().json.subAgente || 'triaje';

// Buscar acción estructurada
const actionMatch = rawText.match(/###ACCION###\n([\s\S]*?)\n###FIN###/);
let accion = null;
let textoLimpio = rawText;

if (actionMatch) {
  try {
    accion = JSON.parse(actionMatch[1].trim());
    textoLimpio = rawText.replace(/###ACCION###[\s\S]*?###FIN###/, '').trim();
  } catch (e) { accion = null; }
}

// SQL para guardar conversación
const sqlGuardar = `INSERT INTO mensajes (conversacion_id, rol, contenido, tipo, twilio_sid, n8n_execution_id) VALUES ((SELECT id FROM conversaciones WHERE paciente_id = ${pacienteId} AND estado = 'activa' LIMIT 1), 'paciente', '${esc(extraer.message)}', 'texto', '${esc(extraer.twilioSid)}', '${$execution.id}'); INSERT INTO mensajes (conversacion_id, rol, contenido, tipo, n8n_execution_id) VALUES ((SELECT id FROM conversaciones WHERE paciente_id = ${pacienteId} AND estado = 'activa' LIMIT 1), 'asistente', '${esc(textoLimpio)}', 'texto', '${$execution.id}');`;

// SQL para log (con sub_agente en nivel)
const sqlLog = `INSERT INTO workflow_logs (workflow_id, workflow_name, execution_id, nivel, mensaje) VALUES ('${$execution.id}', 'WhatsApp Agent', '${$execution.id}', '${esc(subAgente)}', '${esc('Sub-agente: ' + subAgente + ' | Paciente: ' + (pacienteId || '') + ' | ' + textoLimpio.substring(0, 100))}');`;

// SQL para registrar acción
let sqlAccion = null;
if (accion) {
  sqlAccion = `INSERT INTO workflow_logs (workflow_id, workflow_name, execution_id, nivel, mensaje) VALUES ('${$execution.id}', 'WhatsApp Agent', '${$execution.id}', '${esc(subAgente + '_accion')}', '${esc(JSON.stringify(accion))}');`;
}

const responseText = textoLimpio || $input.first().json.responseText || 'Gracias por comunicarte con el consultorio. Te responderemos a la brevedad.';

return [{
  responseText: responseText,
  subAgente: subAgente,
  tieneAccion: accion !== null,
  accionTipo: accion ? accion.tipo : null,
  accionData: accion ? accion.data : null,
  sqlGuardar: sqlGuardar,
  sqlLog: sqlLog,
  sqlAccion: sqlAccion,
  phone: 'whatsapp:' + extraer.phone,
  fromNumber: extraer.fromNumber,
  toNumber: extraer.toNumber,
  profileName: extraer.profileName,
  pacienteId: pacienteId
}];
